<template><el-card shadow="never"><div class="toolbar"><el-input v-model="query" placeholder="任务名称" clearable/><el-select v-if="isAdmin" v-model="creatorAccountId" placeholder="创建账号" clearable filterable @change="load"><el-option v-for="a in accounts" :key="a.id" :label="`${a.username} · ${a.displayName}`" :value="a.id"/></el-select><el-button @click="load">查询</el-button><el-button type="primary" @click="create">新建任务</el-button></div><el-table :data="rows" border><el-table-column prop="name" label="任务名称"/><el-table-column prop="description" label="描述"/><el-table-column label="创建账号" min-width="160"><template #default="{row}"><div>{{row.creatorUsername||'未归属'}}</div><small>{{row.creatorDisplayName}}</small></template></el-table-column><el-table-column label="调度"><template #default="{row}"><el-tag>{{row.scheduleType===1?'定时':'手动'}}</el-tag></template></el-table-column><el-table-column label="操作"><template #default="{row}"><template v-if="row.canEdit"><el-button link @click="edit(row)">编辑</el-button><el-button link type="success" @click="run(row)">立即执行</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template><span v-else class="readonly">只读</span></template></el-table-column></el-table>
<el-dialog v-model="visible" :title="form.id?'编辑任务':'新建任务'" width="900px"><el-steps :active="step" finish-status="success"><el-step title="基本信息"/><el-step title="调度规则"/><el-step title="接收范围"/><el-step title="消息内容"/><el-step title="预览测试"/></el-steps><div class="step-body">
<div v-if="step===0"><el-form label-width="100px"><el-form-item label="任务名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="描述"><el-input v-model="form.description" type="textarea"/></el-form-item></el-form></div>
<div v-if="step===1"><el-form label-width="110px"><el-form-item label="调度方式"><el-select v-model="form.schedule.mode"><el-option label="手动" value="MANUAL"/><el-option label="一次执行" value="ONCE"/><el-option label="每天" value="DAILY"/><el-option label="国家法定工作日" value="WORKDAY"/><el-option label="每周" value="WEEKLY"/><el-option label="每月" value="MONTHLY"/><el-option label="间隔执行" value="INTERVAL"/><el-option label="高级 Cron" value="CRON"/></el-select></el-form-item><el-form-item v-if="form.schedule.mode==='ONCE'" label="执行时间"><el-date-picker v-model="form.schedule.startAt" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item><el-form-item v-if="['DAILY','WORKDAY','WEEKLY','MONTHLY'].includes(form.schedule.mode)" label="执行时间"><el-time-picker v-model="time" format="HH:mm" value-format="HH:mm"/></el-form-item><el-form-item v-if="form.schedule.mode==='WEEKLY'" label="星期"><el-checkbox-group v-model="form.schedule.daysOfWeek"><el-checkbox v-for="(x,i) in ['一','二','三','四','五','六','日']" :key="i" :value="i+1">周{{x}}</el-checkbox></el-checkbox-group></el-form-item><el-form-item v-if="form.schedule.mode==='MONTHLY'" label="日期"><el-select v-model="form.schedule.daysOfMonth" multiple><el-option v-for="i in 31" :key="i" :label="i+'日'" :value="i"/></el-select></el-form-item><el-form-item v-if="form.schedule.mode==='INTERVAL'" label="间隔"><el-input-number v-model="form.schedule.interval" :min="1"/><el-radio-group v-model="form.schedule.intervalUnit"><el-radio value="MINUTE">分钟</el-radio><el-radio value="HOUR">小时</el-radio></el-radio-group></el-form-item><el-form-item v-if="form.schedule.mode==='CRON'" label="Cron"><el-input v-model="form.schedule.cronExpression"/></el-form-item><el-form-item label="时区"><el-input v-model="form.schedule.timezone"/></el-form-item><el-form-item label="重叠执行"><el-radio-group v-model="form.schedule.overlapPolicy"><el-radio value="SKIP">跳过本次</el-radio><el-radio value="QUEUE">排队</el-radio></el-radio-group></el-form-item><el-form-item><el-button @click="schedulePreview">预览未来时间</el-button><span class="preview">{{nextTimes.join('；')}}</span></el-form-item></el-form></div>
<div v-if="step===2"><el-alert v-if="form.message.channel==='GROUP_WEBHOOK'" title="组织成员不一定在目标群内，系统无法保证群内 @ 成功。" type="warning" :closable="false"/><el-form label-width="110px"><el-form-item label="触达渠道"><el-radio-group v-model="form.message.channel"><el-radio value="GROUP_WEBHOOK">群消息推送</el-radio><el-radio value="APP_MESSAGE">应用消息</el-radio></el-radio-group></el-form-item><el-form-item v-if="form.message.channel==='GROUP_WEBHOOK'" label="目标群"><div class="selector-row"><el-select v-model="form.message.webhookIds" multiple collapse-tags :loading="groupsLoading" placeholder="请选择一个或多个目标群"><el-option v-for="r in robots" :key="r.id" :label="r.label||`${r.groupName} · ${r.pushName}`" :value="r.id"/></el-select><el-button :loading="groupsLoading" @click="loadTargetGroups">刷新</el-button></div><el-alert v-if="groupsError" class="local-alert" :title="groupsError" type="error" :closable="false"/><el-empty v-else-if="!groupsLoading&&robots.length===0" :image-size="48" description="暂无可用机器人，请先添加并启用有效 Webhook"/></el-form-item><el-form-item label="选择人员"><el-select v-model="form.message.mentionedUserIds" multiple filterable :loading="peopleLoading"><el-option v-for="p in people" :key="p.wecomUserId" :label="p.name" :value="p.wecomUserId"/></el-select><el-button :loading="peopleLoading" @click="loadPeople">刷新</el-button><el-alert v-if="peopleError" class="local-alert" :title="peopleError" type="error" :closable="false"/></el-form-item><el-form-item v-if="form.message.channel==='GROUP_WEBHOOK'" label="提醒方式"><el-radio-group v-model="form.message.mentionMode"><el-radio value="NONE">不提醒</el-radio><el-radio value="SELECTED">@所选人员</el-radio><el-radio value="ALL">@群内所有人</el-radio></el-radio-group></el-form-item></el-form></div>
<div v-if="step===3"><el-form label-width="110px"><el-form-item label="消息类型"><el-select v-model="form.message.messageType"><el-option v-for="t in types" :key="t.value" :label="t.label" :value="t.value"/></el-select></el-form-item><el-form-item v-if="['text','markdown','markdown_v2'].includes(form.message.messageType)" label="消息正文"><el-input v-model="form.message.content.content" type="textarea" :rows="8" placeholder="可使用 ${task.name} 等变量"/></el-form-item><template v-else-if="form.message.messageType==='news'"><el-form-item label="标题"><el-input v-model="form.message.content.articles[0].title"/></el-form-item><el-form-item label="摘要"><el-input v-model="form.message.content.articles[0].description"/></el-form-item><el-form-item label="跳转链接"><el-input v-model="form.message.content.articles[0].url"/></el-form-item><el-form-item label="图片链接"><el-input v-model="form.message.content.articles[0].picurl"/></el-form-item></template><template v-else-if="form.message.messageType==='template_card'"><el-form-item label="卡片标题"><el-input v-model="form.message.content.main_title.title"/></el-form-item><el-form-item label="卡片描述"><el-input v-model="form.message.content.main_title.desc"/></el-form-item></template><el-form-item v-else label="媒体 ID"><el-input v-model="form.message.content.media_id" placeholder="请先通过媒体上传接口上传"/></el-form-item></el-form></div>
<div v-if="step===4"><el-descriptions border :column="1"><el-descriptions-item label="任务">{{form.name}}</el-descriptions-item><el-descriptions-item label="调度">{{form.schedule.mode}} {{nextTimes.join('；')}}</el-descriptions-item><el-descriptions-item label="渠道">{{form.message.channel}}</el-descriptions-item><el-descriptions-item label="消息预览"><pre>{{messagePreview}}</pre></el-descriptions-item></el-descriptions><el-button @click="doMessagePreview">刷新预览</el-button><el-button type="warning" @click="sendTest">发送测试</el-button></div></div><template #footer><el-button v-if="step>0" @click="step--">上一步</el-button><el-button v-if="step<4" type="primary" @click="step++">下一步</el-button><el-button v-else type="success" @click="save">保存任务</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import{onMounted,reactive,ref,watch}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{listTasks,getTask,createTask,updateTask,deleteTask,executeTask,listPersons,listSelectableRobots,previewSchedule,previewMessage,testMessage,listAccounts}from'@/api';const user=JSON.parse(localStorage.getItem('supervision_user')||'{}'),isAdmin=user.roles?.includes('ADMIN')===true;const rows=ref<any[]>([]),accounts=ref<any[]>([]),creatorAccountId=ref<number|undefined>(),query=ref(''),visible=ref(false),step=ref(0),time=ref('09:00'),nextTimes=ref<string[]>([]),messagePreview=ref(''),people=ref<any[]>([]),robots=ref<any[]>([]),peopleLoading=ref(false),groupsLoading=ref(false),peopleError=ref(''),groupsError=ref('');const types=[{label:'文本',value:'text'},{label:'Markdown',value:'markdown'},{label:'Markdown v2',value:'markdown_v2'},{label:'图片',value:'image'},{label:'图文',value:'news'},{label:'文件',value:'file'},{label:'语音',value:'voice'},{label:'模板卡片',value:'template_card'}];function fresh(){return{id:0,name:'',description:'',schedule:{mode:'MANUAL',ruleVersion:1,timezone:'Asia/Shanghai',times:['09:00'],daysOfWeek:[1,2,3,4,5],daysOfMonth:[1],interval:1,intervalUnit:'HOUR',cronExpression:'0 0 9 * * ?',misfirePolicy:'FIRE_ONCE_NOW',overlapPolicy:'SKIP',holidayPolicy:'NONE',maxRetries:0,retryDelaySeconds:60,retryBackoff:'FIXED'},message:{channel:'GROUP_WEBHOOK',webhookIds:[],messageType:'text',mentionMode:'NONE',mentionedUserIds:[],content:{content:'督办提醒：${task.name}',articles:[{title:'',description:'',url:'',picurl:''}],main_title:{title:'',desc:''},media_id:''}}}}const form=reactive<any>(fresh());watch(time,v=>form.schedule.times=[v]);async function load(){const r=await listTasks({name:query.value,creatorAccountId:creatorAccountId.value,page:1,size:100});rows.value=r.data.data.records}async function loadPeople(){peopleLoading.value=true;peopleError.value='';try{const r=await listPersons();people.value=r.data.data}catch{people.value=[];peopleError.value='组织人员加载失败，可稍后重试；这不会影响目标群选择。'}finally{peopleLoading.value=false}}async function loadTargetGroups(){groupsLoading.value=true;groupsError.value='';try{const r=await listSelectableRobots();robots.value=r.data.data;const selected=form.message.webhookIds||[];if(selected.some((id:number)=>!robots.value.some(x=>x.id===id)))groupsError.value='当前任务保存的部分目标群已停用、收回共享或配置失效，请重新选择。'}catch{robots.value=[];groupsError.value='目标群加载失败，请重试或检查机器人配置。'}finally{groupsLoading.value=false}}function base(){void loadPeople();void loadTargetGroups()}function create(){Object.assign(form,fresh());step.value=0;visible.value=true;base()}async function edit(row:any){const r=await getTask(row.id),d=r.data.data;Object.assign(form,fresh(),{id:d.task.id,name:d.task.name,description:d.task.description});if(d.schedule?.ruleJson)form.schedule=JSON.parse(d.schedule.ruleJson);if(d.task.messageDefinition){form.message=JSON.parse(d.task.messageDefinition);if(!form.message.webhookIds)form.message.webhookIds=form.message.webhookId?[form.message.webhookId]:[]}visible.value=true;base()}async function schedulePreview(){if(form.schedule.mode==='MANUAL')return nextTimes.value=[];const r=await previewSchedule(form.schedule);nextTimes.value=r.data.data}async function doMessagePreview(){const r=await previewMessage(form.message);messagePreview.value=JSON.stringify(r.data.data,null,2)}async function sendTest(){try{const r=await testMessage(form.message),results=Array.isArray(r.data.data)?r.data.data:[r.data.data],success=results.filter((x:any)=>x?.status==='SUCCESS'||x?.success===true).length;ElMessage.success(`测试发送完成：${success}/${results.length} 个目标成功`)}catch(e:any){ElMessage.error(e?.response?.data?.message||'测试发送失败，机器人可能已停用或收回共享')}}async function save(){if(form.message.channel==='GROUP_WEBHOOK'){if(!form.message.webhookIds?.length)return ElMessage.warning('请至少选择一个目标群');const selected=robots.value.filter(x=>form.message.webhookIds.includes(x.id));const duplicate=selected.some((x,i)=>selected.findIndex(y=>y.groupId===x.groupId)!==i);if(duplicate)await ElMessageBox.confirm('同一群选择了多个消息推送，该群可能收到重复消息，确认继续？','重复触达提醒',{type:'warning'})}const recipients=form.message.mentionedUserIds.map((x:string)=>({recipientType:'PERSON',recipientRef:x,mentionMode:form.message.mentionMode}));const payload={name:form.name,description:form.description,scheduleType:form.schedule.mode==='MANUAL'?0:1,schedule:form.schedule,messageDefinition:form.message,recipients,nodes:[]};form.id?await updateTask(form.id,payload):await createTask(payload);visible.value=false;ElMessage.success('已保存');load()}async function run(r:any){await executeTask(r.id);ElMessage.success('已触发')}async function remove(r:any){await ElMessageBox.confirm('确认删除任务？');await deleteTask(r.id);load()}watch(step,v=>{if(visible.value&&v===2)base()});onMounted(async()=>{if(isAdmin){const r=await listAccounts({page:1,size:100});accounts.value=r.data.data.records}load()})</script><style scoped>.toolbar{display:flex;gap:10px;margin-bottom:16px}.toolbar .el-input{width:220px}.toolbar .el-select{width:220px}.step-body{min-height:430px;padding:28px 10px 0}.selector-row{display:flex;gap:8px;width:100%}.local-alert{margin-top:8px;width:100%}.preview{margin-left:12px;color:#606266;font-size:13px}.readonly,small{color:#909399}pre{white-space:pre-wrap;margin:0}</style>
